class_methods.method:
method is
  i   : integer;
  obj : array of object;
  ex  : boolean;
  name: text;
begin
  -- Erfassungsdatum /Erfasser setzen
  i := Modify_Time(Search_View("bisB_CreationDate"), self, Now);
  obj := FilterNavigation('[START PERSON ELSIF = 0 START USER]', [self]);
  if obj.l > 0 then
    Get_Text(Search_View('Object_Display_Kontext'), obj(1), ex, name);
    i := Modify_Text(Search_View('bisB_Creator'), self, name);
  end if;
end;

method (flags: Integer) is
  i   : integer;
  usr : integer;
  date: integer;
  obj : array of object;
  ex  : boolean;
  name: text;
begin
  -- Änderungsdatum / ändernde Person setzen
  usr := Search_View('bisB_ModifiedBy');
  date := Search_View("bisB_ModificationDate");
  if (RequestedAttribute <> usr) and (RequestedAttribute <> date) then
    i := Modify_Time(date, self, Now);
    obj := FilterNavigation('[START PERSON ELSIF = 0 START USER]', [self]);
    if obj.l > 0 then
      Get_Text(Search_View('Object_Display_Kontext'), obj(1), ex, name);
      i := Modify_Text(usr, self, name);
    end if;
  end if;

  ReturnCallInherited;
end;

method is
  contract  : object;
  aktVers   : array of object;
  attrState : integer;
  ex        : boolean;
  val       : time;
  dummy     : integer;
begin
  attrState := Search_View('bisB_ContractState');
  contract := Hop1(self, 'Object_To_Parent');
  if contract /= null then
    aktVers := Hop(contract, Search_Type('bisB_ContractVersion'), 'bisB_ContractToContractVersionLetzteVersion');
    if aktVers.l > 0 then
      Get_Time(attrState, aktVers(1), ex, val);
      if ex then
        dummy := Modify_Time(attrState, contract, val);
      end if;
    end if;
  end if;


end;

