methods.method:
method return Integer is
  state : integer;
  ex   : boolean;
  r  : integer; -- red
  g  : integer; -- green
  b  : integer; -- blue
begin
  Get_Integer(Search_View("bisB_ContractAuslaufstatus"), self, ex, state);
  if ex then
    if state = 30 then  -- ausgelaufen
      r := 255;
      g := 128;   
      b := 128;
    elsif state = 20 then -- in Kündigungsfrist
      r := 255;
      g := 255;
      b := 128;
    elsif state = 10 then -- laufend
      r := 128;
      g := 255;
      b := 128;

    else
      r := 255;
      g := 255;
      b := 255;
    end if;

    return r + 256 * (g + 256 * b);
  end if;

  Raise_Not_Exists;


end;

method return Time is
  res: Time;
  ex : boolean;
  endDate : time;
  dur  : Interval;
begin
  Get_Time(Search_View('bisB_ContractEnd'),SELF,ex,endDate);
  if ex then
    res := endDate;
    Get_Interval(Search_View('bisB_NoticePeriod'),SELF,ex,dur);
    if ex then
      res :=  endDate - dur;
    end if;
    return res;
  end if;
  Raise_Not_Exists;
end;

method return Boolean is
  res                : Boolean;
  ex                 : Boolean;
  automaticRenewal   : Boolean;
  contractEnd        : time;
  contractState      : integer;
  noticePeriod       : interval;
  emailLeadTime      : integer;
  emailLeadTimeIval  : interval;
  ende               : time;
begin
  res := false;
  Get_Integer(Search_View('bisB_ContractState'), self, ex, contractState);
  if ex and (contractState = 1) then -- 1 - laufend
    Get_Boolean(Search_View('bisB_AutomaticRenewal'), self, ex, automaticRenewal);
    if (not automaticRenewal) then  -- keine automatische Verlängerung
      Get_Time(Search_View('bisB_ContractEnd'), self, ex, contractEnd);
      if ex then  -- Vertragsende vorhanden
        Get_Interval(Search_View('bisB_NoticePeriod'), self, ex, noticePeriod);                        
        if not ex then
          noticePeriod := InitInterval(8, 0.0);
        end if;
        Get_Integer(Search_View('bisP_EmailLeadTime'), self, ex, emailLeadTime);
        if not ex then
          emailLeadTime := 0;
        end if;
        emailLeadTimeIval := InitInterval(8, Int_To_Float(emailLeadTime));
        ende := contractEnd - noticePeriod - emailLeadTimeIval;
        put(TimeToText(ende, 'yyyy.mm.dd'));
        res := NOW >= ende;
      end if;
    end if;               
  end if;
  return res;
end;

