method is
  prefix : Text;
  nb : Integer;
  it : Text;
  id : integer;
  maxObj: array of object;
  ex: boolean;
  err: integer;
begin
  id := Search_View("bisB_ContractID");
  prefix:= "SLT";
  maxObj:= FilterNavigation("START MAX bisB_ContractID", [self]);


  id := Search_View("bisB_ContractID");
  maxObj := FilterNavigation("START MAX 'bisB_ContractID'", maxObj);
  nb := 1;
  if maxObj.l <> 0 then
    Get_Text(id, maxObj(1), ex, it);
    if ex then
      it := Substr(it, 3, 6);
      nb := Float_To_Int(Text_To_Float(it)) +1;
    end if;                                                                               
  end if;

  loop
    it := Int_To_Text(nb);
    it :=  prefix & Substr("000000", 1, 6 - it.l) & it;
    exit when (5 /= Modify_Text(id, Self, it));
    nb := nb +1;
  end loop;


  QueueAction(self, 'CreateNewVersion' , false);

end;

method is cmd : text; objs : array of object; begin -- Erstellt eine neue Version, wobei die aktuelle als Vorlage genommen wird cmd := "" & " SAVEAS Contract " & " VIA bisB_ContractToContractVersionLetzteVersion" & " SAVEAS contractVers" & " IF 'COUNT = 0' (" & " CREATE 1 bisB_ContractVersion (RECALL Contract)" & " ELSE" & " SAVEAS status "&#34& "=ATTRIBUTE('bisB_ContractState')" &#34 & " " & " VIA bisB_ContractToObjects" & " SAVEAS zugeordnObj" & " RECALL contractVers" & " VIA bisB_ContractToMaintPlan" & " SAVEAS wartPlan" & " RECALL contractVers" & " COPYOBJECT (RECALL contractVers VIA Object_To_Parent) DEEP" & " BIND bisB_ContractToObjects (RECALL zugeordnObj)" & " BIND bisB_ContractToMaintPlan (RECALL wartPlan)" & " MODIFY bisB_ContractState DATAOF status" & " " & " )" ;
objs := FilterNavigation(cmd, [self]);
end;

