method return Boolean is
  res                : Boolean;
  ex                 : Boolean;
  automaticRenewal   : Boolean;
  contractEnd        : time;
  contractState      : integer;
  noticePeriod       : interval;
  emailLeadTime      : integer;
  emailLeadTimeIval  : interval;
  ende               : time;
begin
  res := false;
  Get_Integer(Search_View('bisB_ContractState'), self, ex, contractState);
  if ex and (contractState = 1) then -- 1 - laufend
    Get_Time(Search_View('bisB_ContractEnd'), self, ex, contractEnd);
    if ex then  -- Vertragsende vorhanden
      Get_Interval(Search_View('bisB_NoticePeriod'), self, ex, noticePeriod); --Kündigungsfrist
      if not ex then
        noticePeriod := InitInterval(8, 0.0);
      end if;
      Get_Integer(Search_View('bisP_EmailLeadTime'), self, ex, emailLeadTime);
      if not ex then
        emailLeadTime := 0;
      end if;
      emailLeadTimeIval := InitInterval(8, Int_To_Float(emailLeadTime));
      ende := contractEnd - noticePeriod - emailLeadTimeIval;
      put(TimeToText(ende, 'yyyy.mm.dd'));
      res := NOW >= ende;
    end if;
  end if;
  return res;
end;

method return Text is
  res: Text;
  attr: integer;
  attrNm: integer;
  err: integer;
  tmp: text;
  ex: boolean;
  i: integer;
  objs: array of object;
begin
  objs:= FilterNavigation("VIA SLT_CM_ContractToBearbeiter  SORT(+Object_Display_Kontext)", [self]);
  if objs.l > 0 then
    attrNm:= Search_View("Object_Display_Kontext");
    i := 1;
    loop
      exit when i > objs.l;
      Get_Text(attrNm, objs(i), ex, tmp);
      if i = 1 then
        res := tmp;
      else
        res := res & ", "  & tmp;
      end if;
      i := i +1;
    end loop;
   return res;
  end if;
  Raise_Not_Exists;
end;

