class_methods.method:
             method is
  prefix : Text;
  i : Integer;
  id : integer;
  s : Text;
  number : Text;
  objs: array of object;
  par : object;
  ex  : boolean;
begin
  par := Hop1(self, 'Object_To_Parent');
  if par /= null then
    Get_Text(Search_View('bisB_ContractVersionId'), par, ex, prefix);
  else
    prefix := 'undefiniert';
  end if;
  put(prefix);

  id := Search_View("bisB_ContractRenewalId");

  s := TimeToText(Now,'YYMM');
  prefix := prefix & "_" & s;
  put(prefix);

  -- wieviele gibt es bereits mit diesem Prefix (intern und extern)?
  objs := Search_Object(id, prefix & '*', true, true);
  i := objs.l;
  put('Anz: ' & Int_To_Text(i) );

  loop                                                                 
    i := i + 1; -- bei "1" beginnen
    number := Int_To_Text(i);
    number := prefix & "_" & Substr("0000", 1, 4 - number.l) & number;
    objs := Search_Object(id, number, true, false); -- schon vorhanden? Log-Eintrag vermeiden!
    if objs.l = 0 then
      exit when (5 /= Modify_Text(id, self, number));
    end if;
  end loop;

end;

method is
  cmd : text;
  newRenewal : object;
  allRenewals : array of object;
  lastRenewals : array of object;
  attr: integer;
  i: integer;
  err: integer;
  start: time;
  ende: time;
  d: interval;
  ex: boolean;
begin
  attr:= Search_View("bisB_ContractEnd");
  Get_Time(attr, self, ex, ende);
  Get_Interval(Search_View("bisB_RenewalPeriod"), self, ex, d);
  allRenewals:=  Hop(self, Search_Type("bisB_ContractRenewal"), "Object_To_Children");
  if allRenewals.l = 0 then
    i:= 1;
  else
    i:= allRenewals.l +1;                                        
  cmd :=  "" &
          " VIA Object_To_Children CLASS bisB_ContractRenewal" &
          " SORT(- bisB_ContractEnd) PICK 0 1 ";
    lastRenewals:= FilterNavigation(cmd, [self]);
    if lastRenewals.l = 1 then
      Get_Time(attr, lastRenewals(1), ex, ende);
    end if;
  end if;
  start:= ende;
  ende:= start +d;
  newRenewal:= CreateObject(Search_Type("bisB_ContractRenewal"), self);
  err:= Modify_Text(Search_View("name"), newRenewal,  Int_To_Text(i) & ". Vertragsverlängerung");
  err:= Modify_Time(Search_View("bisB_ContractBegin"), newRenewal, start);
  err:= Modify_Time(Search_View("bisB_ContractEnd"), newRenewal, ende);


end;

method is
  prefix : Text;
  i : Integer;
  id : integer;
  s : Text;
  number : Text;
  objs: array of object;
  par : object;
  ex  : boolean;
begin
