end;

methods.method:
method return Integer is
  res       : integer;
  ex        : boolean;
  stat      : integer;
  exEnde    : boolean;
  ende      : time;
  exKuend   : boolean;
  kuend     : interval;
  exVerl    : boolean;
  verl      : boolean;
  kuendDate : time;
begin
  res := 0 ;
  Get_Integer(Search_View('bisB_ContractState'), self, ex, stat);
  if ex then
    if stat = 1 then  -- nur laufende Verträge
      Get_Boolean(Search_View('bisB_AutomaticRenewal'), self, exVerl, verl);
      if exVerl and verl then
        res := 10 ; -- 10 = reguläre Laufzeit
      else
        Get_Time(Search_View('bisB_ContractEnd'), self, exEnde, ende);
        Get_Interval(Search_View('bisB_NoticePeriod'), self, exKuend, kuend);
        if exEnde then
          if ende < Now then
            res := 30 ;
          else
            if exKuend then
              kuendDate := ende - kuend;
              if kuendDate <= Now then
                res := 20 ; -- 20 = innerhalb Kündigungsfrist
              else
                res := 10 ; -- 10 = reguläre Laufzeit
              end if; --kuendDate <= Now
            else
              res := 10 ; -- 10 = reguläre Laufzeit
            end if; --exKuend
          end if;  -- ende < Now
        end if; -- exEnde
      end if; --exVerl and verl
    end if;  -- stat = 1
  end if; -- ex

  return res;  
end;

method (inout action: Integer; inout flags: Integer; inout value: Time) is
begin
  QueueAction(self, 'SetContractBegin', false);
end;

method return Time is
  res     : time;
  ex      : boolean;
  attr    : integer;
  auto    : boolean;
  ende    : time;
  newEnde : time;
  verl    : interval;
  allRenewals : array of object;
  lastRenewals : array of object;
  cmd : text;
begin
  attr:= Search_View("bisB_ContractEnd");
  Get_Time(attr, self, ex, ende);
  if ex then
    res := ende;
    Get_Boolean(Search_View('bisB_AutomaticRenewal'), self, ex, auto);
    if auto then
      --automatische Vertragsverlängerung
      Get_Interval(Search_View('bisB_RenewalPeriod'), self, ex, verl);
      if ex then
        newEnde := ende;
        loop
          exit when newEnde >= Now ;
          newEnde := newEnde + verl;
        end loop;
        res := newEnde;
      end if;
    else
 put(" letzte Vertragsverlängerung (Objekte)");
      -- letzte Vertragsverlängerung (Objekte)
      cmd :=  "" &
              " VIA Object_To_Children CLASS bisB_ContractRenewal" &
              " SORT(- bisB_ContractEnd) PICK 0 1 ";
      lastRenewals:= FilterNavigation(cmd, [self]);
      if lastRenewals.l = 1 then
  put(" letzte Vertragsverlängerung (Objekte)");
       Get_Time(attr, lastRenewals(1), ex, ende);
        if ex then
          res := ende;
        end if;
      end if;
    end if;
    return res;
  end if;

  Raise_Not_Exists;
end;

